oxy_webhelp_navlinks = {"azr_evaluate_options_workload_protect-d30753e19615":{"topics":[{"title":"Primary snapshot retention for Azure workloads","shortdesc":"<p class=\"shortdesc\">Primary snapshot retention for Azure workloads ensures data protection and         recoverability by allowing you to set various retention policies, such as retaining hourly,         daily, monthly, and yearly snapshots, to meet compliance, business continuity, and disaster         recovery requirements.<\/p>","href":"saas\/azr_primary_snapshot_retention.html","attributes":{"data-id":"azr_primary_snapshot_retention"},"menu":{"hasChildren":false},"tocID":"azr_primary_snapshot_retention-d30753e19626","topics":[]},{"title":"Archiving of Azure workloads","shortdesc":"<p class=\"shortdesc\">Archiving in <span class=\"ph\">RSC<\/span> tiers Azure virtual machine or managed disk         snapshots to lower-cost storage, ensuring cost savings, compliance, and         security.<\/p>","href":"saas\/azr_archiving_workloads.html","attributes":{"data-id":"azr_archiving_workloads"},"menu":{"hasChildren":false},"tocID":"azr_archiving_workloads-d30753e19637","topics":[]},{"title":"Multiple archival locations for Azure","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> supports multiple archival locations for Azure virtual machines         and managed disks, allowing granular control over data archiving with up to two distinct         archiving policies.<\/p>","href":"saas\/azr_multiple_arch_loc.html","attributes":{"data-id":"azr_multiple_arch_loc"},"menu":{"hasChildren":false},"tocID":"azr_multiple_arch_loc-d30753e19651","topics":[]},{"title":"Replication of Azure snapshots","shortdesc":"<p class=\"shortdesc\">Replication allows snapshots of Azure virtual machines and managed disks to be copied         to another region based on SLA Domain, using APIs to minimize costs. This process ensures         multi-region availability and data protection for virtual machines and managed         disks.<\/p>","href":"saas\/azr_replication_snapshots.html","attributes":{"data-id":"azr_replication_snapshots"},"menu":{"hasChildren":false},"tocID":"azr_replication_snapshots-d30753e19664","topics":[]},{"title":"Retention lock for Azure workloads","shortdesc":"<p class=\"shortdesc\">A retention lock on an <span class=\"ph\">RSC<\/span> SLA Domain is a security feature that         prevents premature deletion of Azure snapshots.<\/p>","href":"saas\/azr_retention_lock.html","attributes":{"data-id":"azr_retention_lock"},"menu":{"hasChildren":false},"tocID":"azr_retention_lock-d30753e19675","topics":[]},{"title":"Azure SQL backup versioning and compliance","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> uses different backup versions based on the backup service         selected in an SLA Domain to manage snapshot retention and ensure data         integrity.<\/p>","href":"saas\/azure_sql_backup_version_compliance.html","attributes":{"data-id":"azure_sql_backup_version_compliance"},"menu":{"hasChildren":false},"tocID":"azure_sql_backup_version_compliance-d30753e19689","topics":[]},{"title":"Multiple key-value tag pair","shortdesc":"<p class=\"shortdesc\">Tag-based assignment automates cloud workload protection by replacing manual         selection with dynamic, multi-layered logic. By using multiple key-value pairs,         organizations can apply either the AND or the OR condition to precisely target high-risk         data while reducing rule complexity.<\/p>","href":"saas\/multiple_key_value_tag_pair_2.html","attributes":{"data-id":"multiple_key_value_tag_pair"},"menu":{"hasChildren":false},"tocID":"multiple_key_value_tag_pair-d30753e19702","topics":[]}]}};